code = """import json, re, math
import pandas as pd

def load_records(x):
    if isinstance(x, str):
        with open(x, 'r') as f:
            return json.load(f)
    return x

clin = load_records(var_call_SPUo7gbdUMi3ySo0HkzAnlXK)
expr = load_records(var_call_01xllMrtgJGRhIOLfjgumNgs)

df_clin = pd.DataFrame(clin)
df_expr = pd.DataFrame(expr)

# Extract TCGA barcode from Patient_description
pat = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')
df_clin['ParticipantBarcode'] = df_clin['Patient_description'].str.extract(pat, expand=False)

df_clin = df_clin.dropna(subset=['ParticipantBarcode','histological_type'])

# Ensure histology not bracketed (already filtered, but keep safe)
df_clin = df_clin[~df_clin['histological_type'].astype(str).str.match(r'^\[.*\]$')]

# Expression: numeric and valid
for c in ['normalized_count']:
    df_expr[c] = pd.to_numeric(df_expr[c], errors='coerce')

df_expr = df_expr.dropna(subset=['ParticipantBarcode','normalized_count'])
df_expr = df_expr[df_expr['normalized_count'] >= 0]

# If multiple samples per participant, average log10(n+1) per participant first
# (avoids overweighting patients with multiple samples)
df_expr['log10_expr'] = (df_expr['normalized_count'] + 1.0).apply(lambda v: math.log10(v))
per_pt = df_expr.groupby('ParticipantBarcode', as_index=False)['log10_expr'].mean()

merged = pd.merge(df_clin[['ParticipantBarcode','histological_type']], per_pt, on='ParticipantBarcode', how='inner')

res = merged.groupby('histological_type').agg(
    n_patients=('ParticipantBarcode','nunique'),
    avg_log10_igf2=('log10_expr','mean')
).reset_index()

res['avg_log10_igf2'] = res['avg_log10_igf2'].map(lambda x: float(f"{x:.4f}"))
res = res.sort_values('histological_type')

out = res.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(out))"""

